import { useState } from "react";
import "./carrucel.css"

function Carrucel() {

    const carrucel = document.querySelector(".carrucel-container");

    const [index, useIndex] = useState(1)

    function scrollizq () {
        carrucel.scrollLeft -= 800
        index++;
    }
    function scrollder () {
        carrucel.scrollLeft += 800
        index++;

    }

    return (
        <section className="index-first">
                <div className="botones">
                    <img onClick={scrollizq} className="btn-left" src="/arrow-left.svg" alt="Flecha Izquierda" />
                    <img onClick={scrollder} className="btn-right" src="/arrow-right.svg" alt="Flecha Izquierda" />
                </div>
            <div className="carrucel-container">

                <div className="carrucel">
                    <img src="/burguer.jpg" alt="Hamburguesa" />
                    <img src="/burguer2.jpg" alt="Hamburguesa" />
                    <img src="/burguer3.jpg" alt="Hamburguesa" />
                    <img src="/burguer4.jpg" alt="Hamburguesa" />
                </div>
            </div>
        </section>
    )
}

export default Carrucel;
